`tests/scripts/audit-fetch.sh`:

```bash
#!/usr/bin/env bash
# Usage: ./tests/scripts/audit-fetch.sh <target1> [target2] ...
# Example: ./tests/scripts/audit-fetch.sh app components lib/hooks lib/stores lib/sync
#
# Flags ALL standalone fetch() calls in client source. Catches:
#   fetch('/api/...')                  (literal)
#   fetch(`/api/...`)                  (backtick)
#   fetch( "/api/..." )                (whitespace)
#   fetch(\n  url\n)                   (multi-line)
#   const url = '/api/x'; fetch(url)   (variable indirection)
#
# By design, this also flags legitimate fetch() in non-API contexts (e.g. fetching
# external CDN). Reviewer must classify each hit. The wrapper `lib/api/client.ts`
# is denylisted because its fetch() is the centralized implementation.
#
# Codex round 6 issue #1: previous regex required `/api` literal in the call site,
# missing variable indirection. This version flags any `\bfetch\s*\(` and relies on
# denylist + reviewer judgment.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
DENY_FILE="$SCRIPT_DIR/scope-denylist.txt"

if ! command -v rg >/dev/null 2>&1; then
  echo "ripgrep (rg) required" >&2
  exit 2
fi

if [ "$#" -lt 1 ]; then
  echo "usage: $0 <dir1> [dir2] ..." >&2
  exit 2
fi

GLOBS=()
while IFS= read -r line; do
  [[ -z "$line" || "$line" =~ ^# ]] && continue
  GLOBS+=("--glob" "!${line}/**" "--glob" "!${line}")
done < "$DENY_FILE"

# Codex round 7 issue #1: ripgrep default regex engine does NOT support lookbehind.
# Use --pcre2 to enable `(?<![\.\w])fetch\s*\(` which excludes prefetch/refetch/method-def.
# Verify rg has PCRE2 support; if not, fall back to two-step grep + filter.
if rg --pcre2 --version >/dev/null 2>&1; then
  rg --no-heading --line-number --color never --pcre2 \
    "(?<![\.\w])fetch\s*\(" \
    "${GLOBS[@]}" \
    --type-add 'tsx:*.tsx' --type-add 'ts:*.ts' --type tsx --type ts \
    "$@" || true
else
  # Fallback: catch all fetch( then filter out prefetch/refetch/method definitions.
  rg --no-heading --line-number --color never \
    "\\bfetch\\s*\\(" \
    "${GLOBS[@]}" \
    --type-add 'tsx:*.tsx' --type-add 'ts:*.ts' --type tsx --type ts \
    "$@" \
    | grep -Ev "\\.(pre|re)?fetch\\s*\\(|prefetch\\s*\\(|refetch\\s*\\(|function\\s+fetch\\s*\\(|async\\s+fetch\\s*\\(" || true
fi
```

Make executable: `chmod +x tests/scripts/audit-fetch.sh`.

