import { type NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/utils/supabase/server";
import { verifyToken } from "@/lib/auth-middleware";
import { sanitizePostgrestValue } from "@/lib/utils/postgrest-sanitize";

export async function GET(request: NextRequest) {
  try {
    const auth = verifyToken(request);
    if (!auth || !auth.isRole("admin")) {
      return NextResponse.json(
        { error: "Không có quyền truy cập" },
        { status: 401 },
      );
    }

    const supabase = createServiceClient();
    const { searchParams } = new URL(request.url);

    const periodYear = parseInt(searchParams.get("period_year") || "");
    const periodMonth = parseInt(searchParams.get("period_month") || "");
    const department = searchParams.get("department");
    const search = searchParams.get("search");
    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "50");
    const offset = (page - 1) * limit;

    if (!periodYear || !periodMonth || periodMonth < 1 || periodMonth > 12) {
      return NextResponse.json(
        { error: "Thiếu hoặc sai tham số period_year/period_month" },
        { status: 400 },
      );
    }

    const { data: periodsData } = await supabase
      .from("attendance_monthly")
      .select("period_year, period_month")
      .order("period_year", { ascending: false })
      .order("period_month", { ascending: false });

    const uniquePeriods = Array.from(
      new Map(
        (periodsData || []).map((p) => [
          `${p.period_year}-${p.period_month}`,
          { year: p.period_year, month: p.period_month },
        ]),
      ).values(),
    );

    const { data: attendanceData, error: attendanceError } = await supabase
      .from("attendance_monthly")
      .select(
        "employee_id, total_hours, total_days, total_meal_ot_hours, total_ot_hours, sick_days, source_file, created_at",
      )
      .eq("period_year", periodYear)
      .eq("period_month", periodMonth);

    if (attendanceError) {
      console.error("Attendance query error:", attendanceError);
      return NextResponse.json(
        { error: "Lỗi truy vấn dữ liệu chấm công" },
        { status: 500 },
      );
    }

    if (!attendanceData || attendanceData.length === 0) {
      return NextResponse.json({
        success: true,
        employees: [],
        pagination: { page, limit, total: 0, totalPages: 0 },
        periods: uniquePeriods,
        totalEmployees: 0,
      });
    }

    const employeeIds = attendanceData.map((a) => a.employee_id);

    let employeeQuery = supabase
      .from("employees")
      .select("employee_id, full_name, department, chuc_vu, is_active", {
        count: "exact",
      })
      .in("employee_id", employeeIds)
      .eq("is_active", true);

    if (department && department !== "all") {
      employeeQuery = employeeQuery.eq("department", department);
    }

    if (search && search.length >= 2) {
      const safeSearch = sanitizePostgrestValue(search);
      if (safeSearch) {
        employeeQuery = employeeQuery.or(
          `employee_id.ilike.%${safeSearch}%,full_name.ilike.%${safeSearch}%`,
        );
      }
    }

    const {
      data: employees,
      error: employeesError,
      count,
    } = await employeeQuery
      .order("department")
      .order("full_name")
      .range(offset, offset + limit - 1);

    if (employeesError) {
      console.error("Employees query error:", employeesError);
      return NextResponse.json(
        { error: "Lỗi truy vấn danh sách nhân viên" },
        { status: 500 },
      );
    }

    const attendanceMap = new Map(
      attendanceData.map((a) => [a.employee_id, a]),
    );

    const employeesWithAttendance = (employees || []).map((emp) => {
      const attendance = attendanceMap.get(emp.employee_id);
      return {
        ...emp,
        attendance: attendance
          ? {
              total_hours: attendance.total_hours,
              total_days: attendance.total_days,
              total_meal_ot_hours: attendance.total_meal_ot_hours,
              total_ot_hours: attendance.total_ot_hours,
              sick_days: attendance.sick_days,
              source_file: attendance.source_file,
              created_at: attendance.created_at,
            }
          : null,
      };
    });

    const { data: deptData } = await supabase
      .from("employees")
      .select("department")
      .in("employee_id", employeeIds)
      .eq("is_active", true);

    const departments = [
      ...new Set((deptData || []).map((d) => d.department)),
    ].sort();

    return NextResponse.json({
      success: true,
      employees: employeesWithAttendance,
      pagination: {
        page,
        limit,
        total: count || 0,
        totalPages: Math.ceil((count || 0) / limit),
      },
      periods: uniquePeriods,
      departments,
      totalEmployees: attendanceData.length,
      currentPeriod: { year: periodYear, month: periodMonth },
    });

// API endpoint for data validation - comparing employees vs payroll data
import { type NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/utils/supabase/server";
import { verifyToken } from "@/lib/auth-middleware";
import { csrfProtection } from "@/lib/security-middleware";

interface ValidationStats {
  totalEmployees: number;
  employeesWithPayroll: number;
  missingEmployees: number;
  percentage: number;
}

interface MissingEmployee {
  employee_id: string;
  full_name: string;
  department: string;
  chuc_vu: string;
  is_active: boolean;
}

interface ValidationResponse {
  success: boolean;
  stats: ValidationStats;
  missingEmployees: MissingEmployee[];
  selectedMonth: string;
  cacheTimestamp?: string;
}

// Cache for 24 hours (24 * 60 * 60 * 1000 ms)
const CACHE_DURATION = 24 * 60 * 60 * 1000;
const cache = new Map<
  string,
  { data: ValidationResponse; timestamp: number }
>();

export async function GET(request: NextRequest) {
  try {
    // Verify authentication - only admin can access
    const auth = verifyToken(request);
    if (!auth) {
      return NextResponse.json(
        { error: "Không có quyền truy cập" },
        { status: 401 },
      );
    }

    // Only admin role can access this endpoint
    if (!auth.isRole("admin")) {
      return NextResponse.json(
        {
          error: "Chỉ admin mới có quyền truy cập trang kiểm tra dữ liệu",
        },
        { status: 403 },
      );
    }

    const { searchParams } = new URL(request.url);
    const month = searchParams.get("month") || getCurrentMonth();
    const forceRefresh = searchParams.get("force_refresh") === "true";

    // Validate month format
    if (!/^\d{4}-\d{2}$/.test(month)) {
      return NextResponse.json(
        {
          error: "Định dạng tháng không hợp lệ. Sử dụng format YYYY-MM",
        },
        { status: 400 },
      );
    }

    // Check cache first (unless force refresh)
    const cacheKey = `validation_${month}`;
    if (!forceRefresh && cache.has(cacheKey)) {
      const cached = cache.get(cacheKey)!;
      const isExpired = Date.now() - cached.timestamp > CACHE_DURATION;

      if (!isExpired) {
        return NextResponse.json({
          ...cached.data,
          cacheTimestamp: new Date(cached.timestamp).toISOString(),
        });
      } else {
        cache.delete(cacheKey);
      }
    }

    const supabase = createServiceClient();

    // Get all active employees
    const { data: allEmployees, error: employeesError } = await supabase
      .from("employees")
      .select("employee_id, full_name, department, chuc_vu, is_active")
      .eq("is_active", true)
      .order("department")
      .order("full_name");

    if (employeesError) {
      console.error("Error fetching employees:", employeesError);
      return NextResponse.json(
        {
          error: "Lỗi khi lấy danh sách nhân viên",
        },
        { status: 500 },
      );
    }

    // Get employees who have payroll data for the selected month
    const { data: employeesWithPayroll, error: payrollError } = await supabase
      .from("payrolls")
      .select("employee_id")
      .eq("salary_month", month);

    if (payrollError) {
      console.error("Error fetching payroll data:", payrollError);
      return NextResponse.json(
        {
          error: "Lỗi khi lấy dữ liệu lương",
        },
        { status: 500 },
      );
    }

    // Create set of employee IDs who have payroll data
    const employeeIdsWithPayroll = new Set(
      employeesWithPayroll?.map((p) => p.employee_id) || [],
    );

    // Find missing employees (those without payroll data)
    const missingEmployees: MissingEmployee[] = (allEmployees || [])
      .filter((emp) => !employeeIdsWithPayroll.has(emp.employee_id))
      .map((emp) => ({
        employee_id: emp.employee_id,
        full_name: emp.full_name,
        department: emp.department,
        chuc_vu: emp.chuc_vu,
        is_active: emp.is_active,
      }));

    // Calculate statistics
    const totalEmployees = allEmployees?.length || 0;
    const employeesWithPayrollCount = employeeIdsWithPayroll.size;
    const missingEmployeesCount = missingEmployees.length;
    const percentage =
      totalEmployees > 0
        ? Math.round((employeesWithPayrollCount / totalEmployees) * 100)
        : 0;

    const stats: ValidationStats = {
      totalEmployees,
      employeesWithPayroll: employeesWithPayrollCount,
      missingEmployees: missingEmployeesCount,
      percentage,
    };

    const response: ValidationResponse = {
      success: true,
      stats,
      missingEmployees,
      selectedMonth: month,
    };

    // Cache the result
    cache.set(cacheKey, {
      data: response,
      timestamp: Date.now(),
    });

    return NextResponse.json(response);
  } catch (error) {
    console.error("Error in data validation API:", error);
    return NextResponse.json(
      {
        error: "Lỗi server khi xử lý yêu cầu",
      },
      { status: 500 },
    );
  }
}

// Helper function to get current month in YYYY-MM format
function getCurrentMonth(): string {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, "0");
  return `${year}-${month}`;
}

