    total_hours: number;
    total_days: number;
    total_meal_ot_hours: number;
    total_ot_hours: number;
    sick_days: number;
  } | null;
}

interface Period {
  year: number;
  month: number;
}

interface ApiResponse {
  success: boolean;
  employees: AttendanceEmployee[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
  periods: Period[];
