      setEmployees(data.employees || []);
      setPeriods(data.periods || []);
      setDepartments(data.departments || []);
      setTotalEmployees(data.totalEmployees || 0);
      setSelectedIds(new Set());
    } catch (err) {
      setError(err instanceof Error ? err.message : "Có lỗi xảy ra");
    } finally {
      setLoading(false);
