588: let onAuthExpired: (() => void) | null = null;
589: export function setOnAuthExpired(handler: () => void) {
590:   onAuthExpired = handler;
591: }
592: 
593: function getToken(): string | null {
594:   if (typeof window === 'undefined') return null;
595:   for (const key of TOKEN_KEYS) {
596:     const v = localStorage.getItem(key);
597:     if (v) return v;
598:   }
599:   return null;
600: }
601: 
602: function clearToken() {
603:   if (typeof window === 'undefined') return;
604:   TOKEN_KEYS.forEach(k => localStorage.removeItem(k));
605:   USER_INFO_KEYS.forEach(k => localStorage.removeItem(k));
606: }
