608: interface RequestOpts {
609:   signal?: AbortSignal;
610:   headers?: Record<string, string>;
611: }
612: 
613: async function request<T>(
614:   method: string,
615:   path: string,
616:   body: unknown | undefined,
617:   opts: RequestOpts = {},
618: ): Promise<T> {
619:   const headers = new Headers(opts.headers);
620:   const token = getToken();
621:   if (token) headers.set('Authorization', `Bearer ${token}`);
622:   if (body !== undefined && !(body instanceof FormData)) {
623:     headers.set('Content-Type', 'application/json');
624:   }
625: 
626:   let response: Response;
627:   try {
628:     response = await fetch(path, {
629:       method,
630:       headers,
631:       body:
632:         body === undefined
633:           ? undefined
634:           : body instanceof FormData
635:             ? body
636:             : JSON.stringify(body),
637:       signal: opts.signal,
638:       credentials: 'include',
639:     });
640:   } catch (err) {
641:     if (err instanceof DOMException && err.name === 'AbortError') throw err;
642:     throw new ApiError(ApiErrorCodes.NETWORK_ERROR, 'Lỗi kết nối mạng');
643:   }
644: 
645:   if (response.status === 401) {
646:     clearToken();
647:     if (onAuthExpired) onAuthExpired();
648:     throw new ApiError(
649:       ApiErrorCodes.AUTH_EXPIRED,
650:       'Phiên đăng nhập đã hết hạn',
651:       401,
652:     );
653:   }
654: 
655:   const text = await response.text();
656:   let parsed: any = null;
657:   if (text) {
658:     try {
659:       parsed = JSON.parse(text);
660:     } catch {
661:       parsed = text;
662:     }
663:   }
664: 
665:   if (!response.ok) {
666:     const code =
667:       (parsed && typeof parsed === 'object' && parsed.code) ||
668:       mapStatusToCode(response.status);
669:     const message =
670:       (parsed && typeof parsed === 'object' && parsed.error) ||
671:       `Lỗi ${response.status}`;
672:     const details = parsed && typeof parsed === 'object' ? parsed.details : undefined;
673:     throw new ApiError(code, message, response.status, details);
674:   }
675: 
676:   return parsed as T;
677: }
678: 
679: function mapStatusToCode(status: number): string {
680:   if (status === 400) return ApiErrorCodes.VALIDATION_ERROR;
681:   if (status === 403) return ApiErrorCodes.FORBIDDEN;
682:   if (status === 404) return ApiErrorCodes.NOT_FOUND;
683:   if (status === 409) return ApiErrorCodes.CONFLICT;
684:   if (status === 429) return ApiErrorCodes.RATE_LIMITED;
685:   if (status >= 500) return ApiErrorCodes.SERVER_ERROR;
686:   return ApiErrorCodes.UNKNOWN;
687: }
